const SK="eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImhlZHVmcHB1bnZzZHhpcXZxYW9kIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzMwODQxNDAsImV4cCI6MjA4ODY2MDE0MH0.vdxae3O9KckMR0Zf-NBqyTkLY5Yfy-eKy7Jw8eLRbu4";
const SH={"apikey":SK,"Authorization":"Bearer "+SK,"Content-Type":"application/json"};

async function api(path,opts={}){const r=await fetch(SU+"/rest/v1"+path,{...opts,headers:{...SH,...(opts.headers||{})}});if(!r.ok)throw new Error(await r.text());if(r.status===204)return null;return r.json();}

// Oil price DB
async function dbLoad(){try{return await api("/oil_prices?select=date,gasoline,kerosene,diesel&order=date.asc");}catch(e){console.error(e);return[];}}
async function dbUpsert(date,g,k,d){await api("/oil_prices",{method:"POST",headers:{...SH,"Prefer":"resolution=merge-duplicates,return=minimal"},body:JSON.stringify({date,gasoline:g,kerosene:k,diesel:d})});}
async function dbDelete(date){await api("/oil_prices?date=eq."+date,{method:"DELETE"});}

// Group buy DB
async function gbLoad(){try{return await api("/group_buys?select=*&order=created_at.desc");}catch{return[];}}
async function gbCreate(data){await api("/group_buys",{method:"POST",headers:{...SH,"Prefer":"return=minimal"},body:JSON.stringify(data)});}
async function gbUpdate(id,data){await api("/group_buys?id=eq."+id,{method:"PATCH",headers:{...SH,"Prefer":"return=minimal"},body:JSON.stringify(data)});}
async function gbDelete(id){await api("/group_buy_entries?group_buy_id=eq."+id,{method:"DELETE"});await api("/group_buys?id=eq."+id,{method:"DELETE"});}
async function geLoad(gbId){try{return await api("/group_buy_entries?group_buy_id=eq."+gbId+"&select=*&order=created_at.asc");}catch{return[];}}
async function geLoadAll(){try{return await api("/group_buy_entries?select=*");}catch{return[];}}
async function geCreate(data){await api("/group_buy_entries",{method:"POST",headers:{...SH,"Prefer":"return=minimal"},body:JSON.stringify(data)});}
async function geDelete(id){await api("/group_buy_entries?id=eq."+id,{method:"DELETE"});}


