function agg(a,d){return{d,g:a.reduce((s,x)=>s+x.g,0)/a.length,k:a.reduce((s,x)=>s+x.k,0)/a.length,di:a.reduce((s,x)=>s+x.di,0)/a.length,open_g:a[0].g,close_g:a[a.length-1].g,high_g:Math.max(...a.map(x=>x.g)),low_g:Math.min(...a.map(x=>x.g)),open_k:a[0].k,close_k:a[a.length-1].k,high_k:Math.max(...a.map(x=>x.k)),low_k:Math.min(...a.map(x=>x.k)),open_di:a[0].di,close_di:a[a.length-1].di,high_di:Math.max(...a.map(x=>x.di)),low_di:Math.min(...a.map(x=>x.di))};}
function toW(data){const w=[];let b=[];data.forEach((d,i)=>{b.push(d);const c=new Date(d.d),n=i<data.length-1?new Date(data[i+1].d):null;if(!n||n.getDay()<=c.getDay()||n-c>5*864e5){w.push(agg(b,b[0].d));b=[];}});if(b.length)w.push(agg(b,b[0].d));return w;}
function toM(data){const r=[];let b=[],cm="";data.forEach(d=>{const ym=d.d.slice(0,7);if(ym!==cm&&b.length){r.push(agg(b,b[0].d));b=[];}cm=ym;b.push(d);});if(b.length)r.push(agg(b,b[0].d));return r;}
function toY(data){const r=[];let b=[],cy="";data.forEach(d=>{const yr=d.d.slice(0,4);if(yr!==cy&&b.length){r.push(agg(b,b[0].d));b=[];}cy=yr;b.push(d);});if(b.length)r.push(agg(b,b[0].d));return r;}
function sma(v,p){return v.map((_,i)=>i<p-1?null:v.slice(i-p+1,i+1).reduce((a,b)=>a+b,0)/p);}
function cRSI(v,p=14){const r=Array(v.length).fill(null);if(v.length<p+1)return r;let ag=0,al=0;for(let i=1;i<=p;i++){const d=v[i]-v[i-1];if(d>0)ag+=d;else al-=d;}ag/=p;al/=p;r[p]=al===0?100:100-100/(1+ag/al);for(let i=p+1;i<v.length;i++){const d=v[i]-v[i-1];ag=(ag*(p-1)+(d>0?d:0))/p;al=(al*(p-1)+(d<0?-d:0))/p;r[i]=al===0?100:100-100/(1+ag/al);}return r;}
function cIch(v){const N=v.length,t=Array(N).fill(null),k=Array(N).fill(null),sA=Array(N).fill(null),sB=Array(N).fill(null),c=Array(N).fill(null);const hl=(s,e)=>{let h=-Infinity,l=Infinity;for(let i=s;i<=e;i++){if(v[i]>h)h=v[i];if(v[i]<l)l=v[i];}return(h+l)/2;};for(let i=0;i<N;i++){if(i>=8)t[i]=hl(i-8,i);if(i>=25)k[i]=hl(i-25,i);if(i>=25&&t[i]!=null&&k[i]!=null){const f=i+26;if(f<N)sA[f]=(t[i]+k[i])/2;}if(i>=51){const f=i+26;if(f<N)sB[f]=hl(i-51,i);}else if(i>=25){const f=i+26;if(f<N)sB[f]=hl(0,i);}if(i>=26)c[i-26]=v[i];}return{tenkan:t,kijun:k,senkouA:sA,senkouB:sB,chikou:c};}
function cMACD(v){const ema=(a,p)=>{const r=[a[0]],k=2/(p+1);for(let i=1;i<a.length;i++)r.push(a[i]*k+r[i-1]*(1-k));return r;};const e12=ema(v,12),e26=ema(v,26),m=e12.map((x,i)=>x-e26[i]),s=ema(m,9),h=m.map((x,i)=>x-s[i]);return{macd:m,signal:s,histogram:h};}
function cBoll(v,p=20,m=2){const mid=sma(v,p),u=Array(v.length).fill(null),l=Array(v.length).fill(null);for(let i=p-1;i<v.length;i++){let sq=0;for(let j=i-p+1;j<=i;j++)sq+=(v[j]-mid[i])**2;const s=Math.sqrt(sq/p);u[i]=mid[i]+m*s;l[i]=mid[i]-m*s;}return{upper:u,mid,lower:l};}

