          <button className={`tb ${ichOn?"on":""}`} onClick={()=>setIchOn(!ichOn)} style={ichOn?{color:"#fb923c",borderColor:"rgba(251,146,60,0.4)",background:"rgba(251,146,60,0.1)"}:{}}>일목균형표</button>
